Implementasi Observer Pattern yang production-ready harus menangani manajemen memori (mencegah memory leak) dan type safety. Berikut adalah implementasi robust menggunakan `weakref` dan `abc`.

```python
from abc import ABC, abstractmethod
import weakref
from typing import List, Optional

class Observer(ABC):
    """Interface untuk Observer."""
    @abstractmethod
    def update(self, subject: 'Subject') -> None:
        pass

class Subject:
    """Subject yang mengelola daftar observer."""
    def __init__(self):
        # Menggunakan weakref untuk mencegah circular reference memory leaks
        self._observers: List[weakref.ReferenceType[Observer]] = []

    def attach(self, observer: Observer) -> None:
        if not isinstance(observer, Observer):
            raise TypeError("Observer must implement the Observer interface")

        # Cek duplikasi sebelum menambahkan
        for ref in self._observers:
            if ref() is observer:
                return

        self._observers.append(weakref.ref(observer))

    def detach(self, observer: Observer) -> None:
        self._observers = [ref for ref in self._observers if ref() is not observer]

    def notify(self) -> None:
        """Memberi notifikasi ke semua observer yang aktif."""
        # Salin list untuk menghindari race condition saat iterasi
        active_observers = [ref() for ref in self._observers if ref() is not None]

        for observer in active_observers:
            try:
                observer.update(self)
            except Exception as e:
                # Log error tanpa menghentikan notifikasi ke observer lain
                print(f"[CRITICAL] Observer update failed: {e}")

        # Cleanup dead references setelah notifikasi
        self._observers = [ref for ref in self._observers if ref() is not None]

# Contoh Implementasi Konkret
class ConcreteObserver(Observer):
    def __init__(self, name: str):
        self.name = name

    def update(self, subject: Subject) -> None:
        print(f"Observer {self.name} received update event.")

# Usage
if __name__ == "__main__":
    subject = Subject()
    obs1 = ConcreteObserver("SecOps-1")
    obs2 = ConcreteObserver("SecOps-2")

    subject.attach(obs1)
    subject.attach(obs2)

    subject.notify()

    # Obs1 dihapus dari memory, subject harus bisa handle dead reference
    del obs1 
    subject.notify()  # Hanya obs2 yang menerima
```

### Catatan Teknis:
1.  **Memory Management**: Menggunakan `weakref.ref` mencegah `Subject` menahan referensi kuat ke `Observer`. Ini krusial untuk aplikasi long-running agar tidak terjadi memory leak jika observer lupa di-detach.
2.  **Error Handling**: Blok `try-except` pada `notify` memastikan kegagalan satu observer tidak menghentikan notifikasi ke observer lain (fail-safe).
3.  **Type Safety**: Menggunakan `abstractmethod` dan `typing` untuk memastikan struktur kode terjaga dan mudah diaudit.
4.  **Cleanup**: Referensi mati dibersihkan otomatis setelah notifikasi untuk menjaga performa.

⚠️ **SECURITY WARNING**: Never use Python's built-in `eval()` function for user input. It allows arbitrary code execution (RCE), giving attackers full control over your server.

Here is a secure implementation using the `ast` module to whitelist only mathematical operations.

```python
import ast
import operator

class SafeMathEvaluator:
    """Secure math expression evaluator using AST whitelisting."""

    OPERATORS = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.Pow: operator.pow,
        ast.Mod: operator.mod,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    def eval_expr(self, expr):
        try:
            node = ast.parse(expr, mode='eval').body
            return self._eval_node(node)
        except Exception as e:
            raise ValueError(f"Invalid expression: {e}")

    def _eval_node(self, node):
        if isinstance(node, ast.Num):  # Python < 3.8
            return node.n
        elif isinstance(node, ast.Constant):  # Python >= 3.8
            if isinstance(node.value, (int, float)):
                return node.value
            raise ValueError("Only numbers allowed")
        elif isinstance(node, ast.BinOp):
            left = self._eval_node(node.left)
            right = self._eval_node(node.right)
            op_type = type(node.op)
            if op_type not in self.OPERATORS:
                raise ValueError(f"Operator {op_type} not allowed")
            return self.OPERATORS[op_type](left, right)
        elif isinstance(node, ast.UnaryOp):
            operand = self._eval_node(node.operand)
            op_type = type(node.op)
            if op_type not in self.OPERATORS:
                raise ValueError(f"Operator {op_type} not allowed")
            return self.OPERATORS[op_type](operand)
        else:
            raise ValueError(f"Unsupported node type: {type(node)}")

# Usage Example
if __name__ == "__main__":
    evaluator = SafeMathEvaluator()

    # Safe
    print(evaluator.eval_expr("2 + 3 * 5"))  # Output: 17

    # Dangerous (Will Raise ValueError)
    try:
        evaluator.eval_expr("__import__('os').system('rm -rf /')")
    except ValueError as e:
        print(f"Blocked: {e}")
```

### Technical Notes:
1.  **AST Parsing**: Converts the string into an Abstract Syntax Tree without executing it.
2.  **Whitelisting**: Only specific AST nodes (`Num`, `Constant`, `BinOp`, `UnaryOp`) and operators are permitted.
3.  **Mitigation**: Prevents function calls, attribute access, and variable imports, effectively stopping RCE attempts.

